.tl-age{font-size:10px;color:var(--muted);flex-shrink:0;min-width:22px}
.tl-text{font-size:11px;line-height:1.4}

/* â”€â”€ INBOX PANEL â”€â”€ */
#inbox-panel{width:240px;display:flex;flex-direction:column;background:var(--bg);border-left:1px solid var(--border);overflow:hidden;flex-shrink:0}
#inbox-hdr{display:flex;justify-content:space-between;align-items:center;padding:10px 12px;background:var(--bg2);border-bottom:1px solid var(--border)}
.inbox-title{font-size:12px;font-weight:700;color:var(--gold);letter-spacing:.4px}
#inbox-badge{min-width:20px;height:18px;border-radius:10px;background:var(--red);color:#fff;font-size:10px;font-weight:700;padding:0 6px;display:none;align-items:center;justify-content:center}
#inbox-badge.show{display:flex}
#inbox-list{flex:1;overflow-y:auto;padding:6px}
.inbox-item{padding:8px 10px;margin-bottom:5px;border:1px solid var(--border);border-radius:6px;cursor:pointer;transition:all var(--t);background:var(--bg2)}
.inbox-item:hover{border-color:var(--gold-dim);transform:translateX(-2px)}
.inbox-item.unread{border-left:3px solid var(--gold)}
.inbox-item.read{opacity:.55}
.inbox-item.bill{border-left-color:var(--orange)}
.inbox-item.news{border-left-color:var(--blue)}
.ii-hdr{display:flex;justify-content:space-between;align-items:baseline;margin-bottom:3px}
.ii-date{font-size:9px;color:var(--muted);text-transform:uppercase;letter-spacing:.4px}
.ii-subject{font-size:11.5px;font-weight:600;line-height:1.35}
.ii-preview{font-size:10px;color:var(--muted);line-height:1.3;margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
@media(max-width:1100px){#inbox-panel{display:none}}

